// ── TK NATIVE CORE ────────────────────────────────────────────────────────
// The mod LOGIC runs as native machine code; JS is only the shell (find the
// object, hand pointers to native). Two backends, tried in order:
//   1. precompiled DLL  (native/tkcore/ -> tkcore.dll) — ships as machine code
//      only, NO source. The committed path. JS resolves the il2cpp api (via
//      symbols.ts), hands it to tk_init, then calls the exports.
//   2. CModule (native/tkcore.c) — compiles C source at runtime; fallback only
//      (its source still lives in memory, so it's protection-lite).
declare const __TK_NATIVE_C__: string;
// guard: loaded directly (no build-time inject) -> this global is undefined.
// `typeof` on an undeclared global is safe (no throw); fall back to "" so the
// CModule path just no-ops and we use the DLL or JS fallback instead.
const TK_NATIVE_CORE: string = (typeof __TK_NATIVE_C__ !== "undefined") ? __TK_NATIVE_C__ : "";

// DLL search paths (dev loads the plain build output; shipping decrypts
// obf/tkcore.dll.enc to a temp path and loads that — see build-native.cjs).
const TK_DLL_PATHS: string[] = [
    "C:\\Users\\admin\\Desktop\\SOHAR\\native\\tkcore\\build\\tkcore.dll",
];
// il2cpp api export names the DLL needs. ORDER == TkApi struct order in il2cpp.h.
const TK_API_NAMES: [string, string][] = [
    ["domain_get", "QLrYQLEZqZq"],
    ["domain_assembly_open", "WguKPdHTlLk"],
    ["assembly_get_image", "nPvukQcbaKV"],
    ["class_from_name", "REMEnSrLCCx"],
    ["class_get_method_from_name", "ZhofzzynqJi"],
    ["class_get_field_from_name", "gsGiZHXKGBh"],
    ["field_get_offset", "uzZyKtAZOQw"],
    ["runtime_invoke", "tCsGnbBlLVM"],
    ["string_new", "DFAWawAeVZF"],
    ["object_get_class", "jodRNaGfHwe"],
    ["thread_attach", "ZqgzzmOOrpp"],
    ["thread_current", "RnDwijqVaSF"],
];
const TK_ABI_VERSION = 1;

function _resolveIl2cppApi(name: string, obf: string): any {
    try {
        const E: any = (Il2Cpp as any).$config && (Il2Cpp as any).$config.exports;
        if (E && typeof E["il2cpp_" + name] === "function") { const p = E["il2cpp_" + name](); if (p && !p.isNull()) return p; }
    } catch (_) {}
    try { const q = (Il2Cpp as any).module.findExportByName(obf); if (q && !q.isNull()) return q; } catch (_) {}
    return null;
}

function _loadNativeDll(): any {
    if (typeof Module === "undefined") return null;
    let mod: any = null;
    for (const p of TK_DLL_PATHS) { try { mod = (Module as any).load(p); if (mod) break; } catch (_) {} }
    if (!mod) return null;
    const exp = (n: string): any => {
        try { if (mod.getExportByName) return mod.getExportByName(n); } catch (_) {}
        try { if (mod.findExportByName) { const p = mod.findExportByName(n); if (p) return p; } } catch (_) {}
        try { return (Module as any).getExportByName(mod.name, n); } catch (_) {}
        return null;
    };
    const pInit = exp("tk_init");
    if (!pInit) return null;
    // build the TkApi pointer table the DLL expects
    const table = Memory.alloc(8 + TK_API_NAMES.length * 8);
    table.writeU32(TK_ABI_VERSION);
    for (let i = 0; i < TK_API_NAMES.length; i++) {
        const p = _resolveIl2cppApi(TK_API_NAMES[i][0], TK_API_NAMES[i][1]);
        if (!p) return null;
        table.add(8 + i * 8).writePointer(p);
    }
    const tk_init = new NativeFunction(pInit, "int", ["pointer"]);
    if (tk_init(table) !== 1) return null;
    return {
        kind: "dll", mod,
        bikeInit: new NativeFunction(exp("tk_bike_init"), "void", ["pointer"]),
        bikeApply: new NativeFunction(exp("tk_bike_apply"), "void", ["pointer", "pointer"]),
        bikeRestore: new NativeFunction(exp("tk_bike_restore"), "void", ["pointer"]),
        hsv2rgb: new NativeFunction(exp("tk_hsv2rgb"), "void", ["float", "float", "float", "pointer"]),
        flyJoystick: new NativeFunction(exp("tk_fly_joystick"), "int", ["pointer", "float", "float", "float", "float", "float", "float", "float"]),
        godOrbit: new NativeFunction(exp("tk_god_orbit"), "void", ["pointer", "pointer", "pointer", "int", "int", "float", "float", "float", "float", "float"]),
        playerAddForce: new NativeFunction(exp("tk_player_addforce"), "int", ["pointer", "float", "float", "float"]),
        // RPC mods (method names baked in the DLL)
        rpcAddForce: new NativeFunction(exp("tk_rpc_addforce"), "int", ["pointer", "float", "float", "float"]),
        rpcAddMoney: new NativeFunction(exp("tk_rpc_addmoney"), "int", ["pointer", "int"]),
        rpcPlayerDie: new NativeFunction(exp("tk_rpc_playerdie"), "int", ["pointer", "int"]),
        rpcSetColorHSV: new NativeFunction(exp("tk_rpc_setcolorhsv"), "int", ["pointer", "float", "float", "float", "float"]),
        rpcTagStinky: new NativeFunction(exp("tk_rpc_tagstinky"), "int", ["pointer"]),
        rpcApplyBuff: new NativeFunction(exp("tk_rpc_applybuff"), "int", ["pointer", "int"]),
        rpcSetTeam: new NativeFunction(exp("tk_rpc_setteam"), "int", ["pointer", "int"]),
        rpcTeleport: new NativeFunction(exp("tk_rpc_teleport"), "int", ["pointer", "float", "float", "float"]),
        rpcSetActive: new NativeFunction(exp("tk_rpc_setactive"), "int", ["pointer", "int"]),
        rpcSetHide: new NativeFunction(exp("tk_rpc_sethide"), "int", ["pointer", "int"]),
        rpcDestroy: new NativeFunction(exp("tk_rpc_destroy"), "int", ["pointer", "int"]),
        rpcStun: new NativeFunction(exp("tk_rpc_stun"), "int", ["pointer", "float"]),
        rpcAwardKill: new NativeFunction(exp("tk_rpc_awardkill"), "int", ["pointer"]),
        rpcPlayerStun: new NativeFunction(exp("tk_rpc_playerstun"), "int", ["pointer", "float", "float", "float", "float", "float", "int"]),
        rpcAddExtForce: new NativeFunction(exp("tk_rpc_addextforce"), "int", ["pointer", "float", "float", "float", "int"]),
        rpcPlayerHit: new NativeFunction(exp("tk_rpc_playerhit"), "int", ["pointer", "int", "float", "float", "float", "int"]),
        rpcPlayVfx: new NativeFunction(exp("tk_rpc_playvfx"), "int", ["pointer", "pointer", "int", "float", "float", "float"]),
    };
}

// helper: pull x,y,z out of a [x,y,z] array or an il2cpp Vector3 value
function _vec3(a: any): [number, number, number] {
    if (Array.isArray(a)) return [a[0], a[1], a[2]];
    if (a && typeof a === "object" && a.field) { try { return [a.field("x").value as number, a.field("y").value as number, a.field("z").value as number]; } catch (_) {} }
    return [0, 0, 0];
}

// ── RPC routing layer ───────────────────────────────────────────────────────
// Each mod's JS shell calls R.<rpc>(obj, ...numbers). When the DLL is loaded the
// call (and the method-name choice + invoke) executes as machine code; otherwise
// it falls back to the JS bridge so the menu still works everywhere.
const R = {
    // accepts (obj, x, y, z) OR (obj, vec) where vec is a [x,y,z] array or an
    // il2cpp Vector3 value — call sites pass a single Vector3, so normalize here.
    addForce(obj: any, a: any, b?: number, c?: number): void {
        let x: number, y: number, z: number;
        if (b === undefined) {
            if (Array.isArray(a)) { x = a[0]; y = a[1]; z = a[2]; }
            else if (a && typeof a === "object" && a.field) { try { x = a.field("x").value as number; y = a.field("y").value as number; z = a.field("z").value as number; } catch (_) { x = y = z = 0; } }
            else { x = y = z = 0; }
        } else { x = a as number; y = b as number; z = c as number; }
        const nc = getNativeCore();
        if (nc && nc.rpcAddForce) { try { if (nc.rpcAddForce(obj.handle, x, y, z)) return; } catch (_) {} }
        try { obj.method("RPC_AddForce").invoke([x, y, z]); } catch (_) {}
    },
    addMoney(obj: any, amount: number): void {
        const nc = getNativeCore();
        if (nc && nc.rpcAddMoney) { try { if (nc.rpcAddMoney(obj.handle, amount | 0)) return; } catch (_) {} }
        try { obj.method("RPC_AddPlayerMoney").invoke(amount | 0); } catch (_) {}
    },
    playerDie(obj: any, isDie: boolean): void {
        const nc = getNativeCore();
        if (nc && nc.rpcPlayerDie) { try { if (nc.rpcPlayerDie(obj.handle, isDie ? 1 : 0)) return; } catch (_) {} }
        try { obj.method("RPC_DoPlayerDie").invoke(isDie); } catch (_) {}
    },
    setColorHSV(obj: any, dur: number, h: number, s: number, v: number): void {
        const nc = getNativeCore();
        if (nc && nc.rpcSetColorHSV) { try { if (nc.rpcSetColorHSV(obj.handle, dur, h, s, v)) return; } catch (_) {} }
        try { obj.method("RPC_SetColorHSV").invoke(dur, h, s, v); } catch (_) {}
    },
    tagStinky(obj: any): void {
        const nc = getNativeCore();
        if (nc && nc.rpcTagStinky) { try { if (nc.rpcTagStinky(obj.handle)) return; } catch (_) {} }
        try { obj.method("RPC_TagAsStinky").invoke(); } catch (_) {}
    },
    applyBuff(obj: any, buffID: number): void {
        const nc = getNativeCore();
        if (nc && nc.rpcApplyBuff) { try { if (nc.rpcApplyBuff(obj.handle, buffID | 0)) return; } catch (_) {} }
        try { obj.method("RPC_ApplyBuff", 1).invoke(buffID | 0); } catch (_) {}
    },
    setTeam(obj: any, team: number): void {
        const nc = getNativeCore();
        if (nc && nc.rpcSetTeam) { try { if (nc.rpcSetTeam(obj.handle, team | 0)) return; } catch (_) {} }
        try { obj.method("RPC_SetTeam").invoke(team | 0); } catch (_) {}
    },
    teleport(obj: any, v: any): void {
        const [x, y, z] = _vec3(v);
        const nc = getNativeCore();
        if (nc && nc.rpcTeleport) { try { if (nc.rpcTeleport(obj.handle, x, y, z)) return; } catch (_) {} }
        try { obj.method("RPC_Teleport").invoke([x, y, z]); } catch (_) {}
    },
    setActive(obj: any, active: boolean): void {
        const nc = getNativeCore();
        if (nc && nc.rpcSetActive) { try { if (nc.rpcSetActive(obj.handle, active ? 1 : 0)) return; } catch (_) {} }
        try { obj.method("RPC_SetActive").invoke(active); } catch (_) {}
    },
    setHide(obj: any, hide: boolean): void {
        const nc = getNativeCore();
        if (nc && nc.rpcSetHide) { try { if (nc.rpcSetHide(obj.handle, hide ? 1 : 0)) return; } catch (_) {} }
        try { obj.method("RPC_SetHide").invoke(hide); } catch (_) {}
    },
    destroy(obj: any, sourcePlayerID: number = 0): void {
        const nc = getNativeCore();
        if (nc && nc.rpcDestroy) { try { if (nc.rpcDestroy(obj.handle, sourcePlayerID | 0)) return; } catch (_) {} }
        try { obj.method("RPC_Destroy").invoke(sourcePlayerID | 0); } catch (_) {}
    },
    stun(obj: any, duration: number): void {
        const nc = getNativeCore();
        if (nc && nc.rpcStun) { try { if (nc.rpcStun(obj.handle, duration)) return; } catch (_) {} }
        try { obj.method("RPC_Stun").invoke(duration); } catch (_) {}
    },
    awardKill(obj: any): void {
        const nc = getNativeCore();
        if (nc && nc.rpcAwardKill) { try { if (nc.rpcAwardKill(obj.handle)) return; } catch (_) {} }
        try { obj.method("RPC_AwardKill").invoke(); } catch (_) {}
    },
    playerStun(obj: any, pos: any, range: number, duration: number, atten: number): void {
        const [x, y, z] = _vec3(pos);
        const nc = getNativeCore();
        if (nc && nc.rpcPlayerStun) { try { if (nc.rpcPlayerStun(obj.handle, x, y, z, range, duration, atten | 0)) return; } catch (_) {} }
        try { obj.method("RPC_PlayerStun", 4).invoke([x, y, z], range, duration, atten | 0); } catch (_) {}
    },
    addExtForce(obj: any, force: any, mode: number): void {
        const [x, y, z] = _vec3(force);
        const nc = getNativeCore();
        if (nc && nc.rpcAddExtForce) { try { if (nc.rpcAddExtForce(obj.handle, x, y, z, mode | 0)) return; } catch (_) {} }
        try { obj.method("RPC_AddExternalForce").invoke([x, y, z], mode | 0); } catch (_) {}
    },
    // force + sourceInfo are baked zero in native (every call site passes zero);
    // they're kept here only for the JS fallback path.
    playerHit(obj: any, damage: number, pos: any, force: any, sourceInfo: any, isDeathHit: boolean): void {
        const [x, y, z] = _vec3(pos);
        const nc = getNativeCore();
        if (nc && nc.rpcPlayerHit) { try { if (nc.rpcPlayerHit(obj.handle, damage | 0, x, y, z, isDeathHit ? 1 : 0)) return; } catch (_) {} }
        try { obj.method("RPC_PlayerHit", 5).invoke(damage | 0, [x, y, z], force, sourceInfo, isDeathHit); } catch (_) {}
    },
    // static RPC on the ParticleManager/VFXManager CLASS; rot is always identity.
    // cls = the il2cpp class, runner = NetworkRunner object. rot kept for fallback.
    playVfx(cls: any, runner: any, vfx: number, pos: any, rot?: any): boolean {
        const [x, y, z] = _vec3(pos);
        const nc = getNativeCore();
        if (nc && nc.rpcPlayVfx) { try { if (nc.rpcPlayVfx(cls.handle, runner.handle, vfx | 0, x, y, z)) return true; } catch (_) {} }
        try { cls.method("RPC_PlayVFX", 4).invoke(runner, vfx | 0, [x, y, z], rot || [0, 0, 0, 1]); return true; } catch (_) { return false; }
    },
};

let _nativeCore: any = null;
let _nativeTried = false;
function getNativeCore(): any {
    if (_nativeTried) return _nativeCore;
    _nativeTried = true;
    // 1) precompiled DLL (source-free machine code) — committed path
    try {
        const dll = _loadNativeDll();
        if (dll) { _nativeCore = dll; console.log("[tkcore] native core online (precompiled DLL, machine code)"); return _nativeCore; }
    } catch (e) { console.error("[tkcore] DLL load failed, trying CModule:", e); }
    // 2) CModule fallback (compiles tkcore.c at runtime; source-in-memory)
    try {
        if (typeof CModule === "undefined") throw new Error("CModule unavailable");
        const cm: any = new (CModule as any)(TK_NATIVE_CORE);
        _nativeCore = {
            kind: "cmodule", cm,
            bikeInit: new NativeFunction(cm.tk_bike_init, "void", ["pointer"]),
            bikeApply: new NativeFunction(cm.tk_bike_apply, "void", ["pointer", "pointer"]),
            bikeRestore: new NativeFunction(cm.tk_bike_restore, "void", ["pointer"]),
            hsv2rgb: new NativeFunction(cm.tk_hsv2rgb, "void", ["float", "float", "float", "pointer"]),
            flyJoystick: new NativeFunction(cm.tk_fly_joystick, "int", ["pointer", "float", "float", "float", "float", "float", "float", "float"]),
            godOrbit: new NativeFunction(cm.tk_god_orbit, "void", ["pointer", "pointer", "pointer", "int", "int", "float", "float", "float", "float", "float"]),
        };
        console.log("[tkcore] native core online (CModule fallback)");
    } catch (e) {
        _nativeCore = null;
        console.error("[tkcore] native core unavailable, JS fallback:", e);
    }
    return _nativeCore;
}

let _bikeOffsetsSet = false;
function ensureBikeOffsets(cfgClass: any): boolean {
    if (_bikeOffsetsSet) return true;
    const nc = getNativeCore();
    if (!nc) return false;
    try {
        const buf = Memory.alloc(BIKE_TUNE_FIELDS.length * 4);
        for (let i = 0; i < BIKE_TUNE_FIELDS.length; i++) {
            const f = cfgClass.field(BIKE_TUNE_FIELDS[i]);
            if (!f) return false;
            buf.add(i * 4).writeInt(f.offset);
        }
        nc.bikeInit(buf);
        _bikeOffsetsSet = true;
        return true;
    } catch (e) { console.error("ensureBikeOffsets:", e); return false; }
}

// per-field multiplier array; order MUST match BIKE_TUNE_FIELDS and the C above
function bikeMultArray(): number[] {
    const m = bikeMults;
    const inv = 1 / Math.max(0.1, m.steer1h);   // more steer feel => less smoothing/deadzone
    return [m.speed, m.reverse, m.climb, m.turn, m.turn, m.steerTorque, m.grip, m.damping, m.level, m.level, m.steer1h, inv, inv];
}

function findBikeConfigs(): any[] {
    const out: any[] = [];
    try {
        const img = Il2Cpp.domain.assembly("AnimalCompany").image;
        let klass: any = null;
        try { klass = img.class("AnimalCompany.SpacebikeController"); } catch (_) {}
        if (!klass) { try { klass = img.class("AnimalCompany.SpaceshipController"); } catch (_) {} }
        if (!klass) return out;
        for (const inst of Il2Cpp.gc.choose(klass)) {
            try {
                const cfg = inst.field("_config").value;
                if (cfg && !cfg.isNull?.()) out.push(cfg);
            } catch (_) {}
        }
    } catch (e) { console.error("findBikeConfigs:", e); }
    return out;
}

function applyBikeTuning(): number {
    const cfgs = findBikeConfigs();
    if (cfgs.length === 0) return 0;
    const nc = getNativeCore();
    for (const cfg of cfgs) {
        try {
            if (nc && ensureBikeOffsets(cfg.class)) {
                const arr = bikeMultArray();
                const mult = Memory.alloc(arr.length * 4);
                for (let i = 0; i < arr.length; i++) mult.add(i * 4).writeFloat(arr[i]);
                nc.bikeApply(cfg.handle, mult);   // <-- logic executes as machine code, not JS
            } else {
                applyBikeTuningJS(cfg);           // fallback if native unavailable
            }
        } catch (e) { console.error("applyBikeTuning:", e); }
    }
    return cfgs.length;
}

// JS fallback only — used if CModule isn't available on a machine.
function applyBikeTuningJS(cfg: any): void {
    const m = bikeMults;
    if (!bikeOrigConfig) {
        bikeOrigConfig = {};
        for (const f of BIKE_TUNE_FIELDS) { try { bikeOrigConfig[f] = cfg.field(f).value; } catch (_) {} }
    }
    const o = bikeOrigConfig;
    const setF = (name: string, v: number) => { try { cfg.field(name).value = v; } catch (_) {} };
    setF("forwardThrust", o.forwardThrust * m.speed);
    setF("reverseThrust", o.reverseThrust * m.reverse);
    setF("climbAccel", o.climbAccel * m.climb);
    setF("yawRateAtRest", o.yawRateAtRest * m.turn);
    setF("yawRateAtMaxSpeed", o.yawRateAtMaxSpeed * m.turn);
    setF("yawTorqueGain", o.yawTorqueGain * m.steerTorque);
    setF("lateralGripRate", o.lateralGripRate * m.grip);
    setF("linearDamping", o.linearDamping * m.damping);
    setF("levelingStiffness", o.levelingStiffness * m.level);
    setF("levelingDamping", o.levelingDamping * m.level);
    setF("oneHandedSteerScale", o.oneHandedSteerScale * m.steer1h);
    setF("oneHandedSteerSmoothing", Math.max(0.01, o.oneHandedSteerSmoothing / Math.max(0.1, m.steer1h)));
    setF("oneHandedSteerDeadzone", o.oneHandedSteerDeadzone / Math.max(0.1, m.steer1h));
}

function restoreBikeTuning(): void {
    const nc = getNativeCore();
    for (const cfg of findBikeConfigs()) {
        try {
            if (nc && _bikeOffsetsSet) { nc.bikeRestore(cfg.handle); }   // native restore
            else if (bikeOrigConfig) { for (const f of BIKE_TUNE_FIELDS) if (f in bikeOrigConfig) cfg.field(f).value = (bikeOrigConfig as any)[f]; }
        } catch (_) {}
    }
}

function cycleBikeMult(key: string): void {
    let i = BIKE_MULT_STEPS.indexOf(bikeMults[key]);
    if (i < 0) i = BIKE_MULT_STEPS.indexOf(2);
    bikeMults[key] = BIKE_MULT_STEPS[(i + 1) % BIKE_MULT_STEPS.length];
    if (bikeTuningOn) applyBikeTuning();
}

