    let _spawnGuardTester: any = null;
    function spawnMobBypass(mobEntry: { name: string; id: number }): boolean {
        try {
            const cls = AssemblyCSharp.class("AnimalCompany.SpawnGuardTester");
            if (!cls) { console.error("[mobBypass] no SpawnGuardTester class"); return false; }
            if (!_spawnGuardTester || _spawnGuardTester.isNull?.()) {
                let found: any = null;
                try { found = Object.method("FindObjectOfType", 0).inflate(cls).invoke(); } catch(_) {}
                if (found && !found.isNull?.()) _spawnGuardTester = found;
                else {
                    const host = createEmptyObject("TKSpawnGuard", null);
                    try { Object.method("DontDestroyOnLoad", 1).invoke(host); } catch(_) {}
                    _spawnGuardTester = addComponent(host, cls);
                }
            }
            if (!_spawnGuardTester || _spawnGuardTester.isNull?.()) return false;
            try { _spawnGuardTester.field("_testMobID").value = mobEntry.id | 0; } catch(_) {}
            try { _spawnGuardTester.field("_spawnDistance").value = 3.0; } catch(_) {}
            try { _spawnGuardTester.field("_burstCount").value = 1; } catch(_) {}
            acEnableMobValidatorBypass();
            _spawnGuardTester.method("SpawnIllegalMob").invoke();
            return true;
        } catch(e) { console.error("[mobBypass]", e); return false; }
    }
    function getMobPrefabNames(mobEntry: { name: string; id: number }): string[] {
        const names: string[] = [];
        const push = (s: any) => { const v = (typeof s === "string" ? s : (s?.content ?? "")).replace(/"/g, "").trim(); if (v && v !== "null" && v !== "?" && names.indexOf(v) < 0) names.push(v); };
        try {
            if (MobDataUtilityClass) {
                for (const oc of [-1, 1]) {
                    try {
                        const nameObj = oc < 0 ? MobDataUtilityClass.method("GetMobPrefabName").invoke(mobEntry.id) : MobDataUtilityClass.method("GetMobPrefabName", 1).invoke(mobEntry.id);
                        push(nameObj);
                    } catch(_) {}
                }
            }
        } catch(_) {}
        try {
            const sheet = AssemblyCSharp.class("AnimalCompany.MobPrefabSheet").method("get_instance").invoke();
            if (sheet && !sheet.isNull?.()) {
                try { sheet.method("UpdateLookup").invoke(); } catch(_) {}
                let mobID = acResolveMobID(mobEntry.id);
                if (mobID == null) mobID = acResolveMobID(mobEntry.name);
                if (mobID == null) mobID = mobEntry.id;
                const ctrl = sheet.method("GetByMobID", 1).invoke(mobID);
                if (ctrl && !ctrl.isNull?.()) {
                    try { push(ctrl.method("get_gameObject").invoke().method("get_name").invoke()); } catch(_) {}
                }
            }
        } catch(_) {}
        const clean = String(mobEntry.name).replace(/^mob_prefab\//, "");
        push(clean); push(clean + "Controller"); push("mob_prefab/" + clean); push("mob_" + clean);
        return names;
    }
    function trySpawnPrefabByName(name: string, pos: any, rot: any): any {
        try {
            if (!didInitPrefabs) initPrefabs();
            if (!prefabNameMap.has(name)) return null;
            const r = spawnPrefab(name, pos, rot);
            return (r && !r.isNull?.()) ? r : null;
        } catch(_) { return null; }
    }
    // bypassed mob spawn: skips the area-gated SpawnMobAsync and spawns the mob's prefab directly.
    // uses spawnPrefab first (passes local authority - works in the hub) then spawnNetworkPrefab.
    function spawnMobFusion(mobEntry: { name: string; id: number }, pos: any, rot: any): any {
        try {
            acEnableMobValidatorBypass();
            const r = rot || identityQuaternion;
            for (const name of getMobPrefabNames(mobEntry)) {
                let spawned = trySpawnPrefabByName(name, pos, r);
                if (!spawned) { try { spawned = spawnNetworkPrefab(name, pos, r); } catch(_) {} }
                if (spawned && !spawned.isNull?.()) {
                    try { stabilizeMobInstance(spawned, pos); } catch(_) {}
                    spawnedPersistentMobs.push(spawned);
                    try { trackPersistentMob(mobEntry, pos, rot, spawned); } catch(_) {}
                    return spawned;
                }
            }
            console.error("[mobFusion] no prefab spawned for " + mobEntry.name + " (tried: " + getMobPrefabNames(mobEntry).join(", ") + ")");
            return null;
        } catch(e) { console.error("spawnMobFusion:", e); return null; }
    }
    function installSteamVRBypass(): void {
        try {
            const ac = Il2Cpp.domain.assembly("AnimalCompany").image;
            const appUtils = ac.class("AnimalCompany.AppUtils");
            const status = appUtils.nested("SteamVRHeadsetStatus");
            try { appUtils.method("IsSteamVRHeadsetActive").implementation = function () { return true; }; } catch(e) { console.error("[vrbypass] IsSteamVRHeadsetActive", e); }
            try { appUtils.method("GetXRBackend").implementation = function () { return 2; }; } catch(e) { console.error("[vrbypass] GetXRBackend", e); }
            try {
                appUtils.method("GetSteamVRHeadsetStatus").implementation = function () {
                    const spoof = status.new().unbox();
                    try { spoof.field("activeLoaderPresent").value = true; } catch(_) {}
                    try { spoof.field("xrDisplayRunning").value  = true; } catch(_) {}
                    try { spoof.field("headDeviceValid").value   = true; } catch(_) {}
                    try { spoof.field("userPresenceKnown").value = true; } catch(_) {}
                    try { spoof.field("userPresent").value       = true; } catch(_) {}
                    return spoof;
                };
            } catch(e) { console.error("[vrbypass] GetSteamVRHeadsetStatus", e); }
            console.log("[vrbypass] SteamVR headset checks bypassed (no-HMD spoof active)");
        } catch(e) { console.error("[vrbypass] failed: " + e); }
    }

    let desktopMenuOpen = false;
    let desktopSelIndex = 0;
    let desktopVisibleCount = 0;
    let currentVisibleButtons: any[] = [];
    let _deskReady = false;
    let _GetAsyncKeyState: any = null;
    let _GetCursorPos: any = null;
    let _GetSystemMetrics: any = null;
    let _deskPoint: any = null;
    let _deskScreenH = 1080;
    const _deskKeyPrev: Record<number, boolean> = {};

    function _u32Export(name: string): any {
        const M: any = Module, P: any = Process;
        try { return P.getModuleByName("user32.dll").getExportByName(name); } catch(_) {}
        try { return M.getGlobalExportByName?.(name); } catch(_) {}
        try { return M.getExportByName("user32.dll", name); } catch(_) {}
        return null;
    }
    function setupDesktopInput(): void {
        if (_deskReady) return;
        const M: any = Module, P: any = Process, NF: any = NativeFunction;
        try {
            try { if (!P.findModuleByName?.("user32.dll")) M.load("user32.dll"); } catch(_) {}
            _GetAsyncKeyState = new NF(_u32Export("GetAsyncKeyState"), "int16", ["int"]);
            _GetCursorPos     = new NF(_u32Export("GetCursorPos"), "int", ["pointer"]);
            _GetSystemMetrics = new NF(_u32Export("GetSystemMetrics"), "int", ["int"]);
            _deskPoint = Il2Cpp.alloc(8);
            try { _deskScreenH = _GetSystemMetrics(1) || 1080; } catch(_) {}
            _deskReady = true;
            console.log("[desktop] input ready — Q toggles menu, move mouse to highlight, left-click to press, right-click/Backspace to go back, mouse side buttons / arrows for pages");
        } catch(e) { console.error("[desktop] input setup failed: " + e); }
    }
    function _deskDown(vk: number): boolean { try { return (_GetAsyncKeyState(vk) & 0x8000) !== 0; } catch(_) { return false; } }
    function _deskPressed(vk: number): boolean {
        const d = _deskDown(vk);
        const was = _deskKeyPrev[vk] || false;
        _deskKeyPrev[vk] = d;
        return d && !was;
    }
    function _deskMouseY(): number {
        try { if (_GetCursorPos(_deskPoint)) return _deskPoint.add(4).readInt(); } catch(_) {}
        return -1;
    }
    function _deskChangePage(dir: number): void {
        try {
            const arr = buttons[currentCategory];
            if (!arr) return;
            const lastPage = Math.max(0, Math.ceil(arr.length / 8) - 1);
            currentPage += dir;
            if (currentPage < 0) currentPage = lastPage;
            if (currentPage > lastPage) currentPage = 0;
            desktopSelIndex = 0;
        } catch(_) {}
    }
    function pollDesktopInput(): void {
        if (!_deskReady) return;
        if (_deskPressed(0x51)) {
            desktopMenuOpen = !desktopMenuOpen;
            desktopSelIndex = 0;
            try { sendNotification(desktopMenuOpen ? "desktop menu OPEN" : "desktop menu CLOSED", false); } catch(_) {}
        }
        if (!desktopMenuOpen) return;
        const count = desktopVisibleCount || 0;
        let changed = false;
        if (count > 0) {
            const y = _deskMouseY();
            if (y >= 0) {
                let slot = Math.floor((y / Math.max(1, _deskScreenH)) * count);
                if (slot < 0) slot = 0;
                if (slot >= count) slot = count - 1;
                if (slot !== desktopSelIndex) { desktopSelIndex = slot; changed = true; }
            }
        }
        if (count > 0 && _deskPressed(0x26)) { desktopSelIndex = (desktopSelIndex - 1 + count) % count; changed = true; }
        if (count > 0 && _deskPressed(0x28)) { desktopSelIndex = (desktopSelIndex + 1) % count; changed = true; }
        if (_deskPressed(0x25) || _deskPressed(0x05)) { _deskChangePage(-1); changed = true; }
        if (_deskPressed(0x27) || _deskPressed(0x06)) { _deskChangePage(1);  changed = true; }
        if (_deskPressed(0x02) || _deskPressed(0x08)) { currentCategory = 11; currentPage = 0; desktopSelIndex = 0; changed = true; }
        if (_deskPressed(0x01) || _deskPressed(0x0D)) {
            const target = currentVisibleButtons[desktopSelIndex];
            if (target) { try { activateMenuButton(target); } catch(e) { console.error("[desktop] activate: " + e); } }
            return;
        }
        if (changed) { try { reloadMenu(); } catch(_) {} }
    }
    function activateMenuButton(button: any): void {
        if (!button) return;
        try { playButtonFeedback(); } catch(_) {}
        if (button.isTogglable) {
            button.enabled = !button.enabled;
            reloadMenu();
            if (button.enabled) {
                if (button.toolTip) sendNotification("[ENABLE] " + button.toolTip, false);
                try { button.enableMethod?.(); } catch(e) { button.enabled = false; console.error(`[Toggle Enable] ${button.buttonText}:`, e); }
            } else {
                if (button.toolTip) sendNotification("[DISABLE] " + button.toolTip, false);
                try { button.disableMethod?.(); } catch(e) { console.error(`[Toggle Disable] ${button.buttonText}:`, e); }
            }
        } else {
            try { button.method?.(); } catch(e) { console.error(`[Button] ${button.buttonText}:`, e); }
            reloadMenu();
            if (button.toolTip) sendNotification(button.toolTip, false);
        }
    }

    let explosionIdOverride = -1;
    let oreDataByte = 0;
    let oreCountByte = 5;
    let treeIdByte = 0;
    let treeHealth = 100;
    let treeSizeByte = 2;
    let claimItemId = "item_timebomb";
    let claimScaleMod = 0;

    function frontOfPlayer(dist: number): any {
        try {
            const headTf = getTransform(headCollider);
            const fwd = readVec3Components(headTf.method("get_forward").invoke());
            const fm = Math.sqrt(fwd[0] * fwd[0] + fwd[2] * fwd[2]) || 1;
            return Vector3.method("op_Addition", 2).invoke(
                getTransform(bodyCollider).method("get_position").invoke(),
                [(fwd[0] / fm) * dist, 0.5, (fwd[2] / fm) * dist]
            );
        } catch(_) {
            try { return getTransform(bodyCollider).method("get_position").invoke(); } catch(_) { return zeroVector; }
        }
    }
    function tkGetRunner(): any {
        try { const c = getRunnerCandidates(); if (c && c.length) return c[0]; } catch(_) {}
        try { return PrefabGen.field("_instance").value.method("get_runner").invoke(); } catch(_) {}
        return null;
    }
    function rpcOnAllOfType(className: string, rpcName: string, argsBuilder: ((inst: any) => any[] | null) | null, label: string): boolean {
        try {
            const cls = AssemblyCSharp.class(className);
            if (!cls) { sendNotification(label + ": class missing", false); return false; }
            const all = Object.method("FindObjectsByType", 1).inflate(cls).invoke(0);
            if (!all || all.length === 0) { sendNotification(label + ": none in this map", false); return false; }
            let n = 0;
            for (let i = 0; i < all.length; i++) {
                const inst = all.get(i);
                if (!inst || inst.isNull?.()) continue;
                try { const no = inst.method("get_Object").invoke(); if (no && !no.isNull?.()) no.method("RequestStateAuthority").invoke(); } catch(_) {}
                let args: any[] | null = [];
                try { args = argsBuilder ? argsBuilder(inst) : []; } catch(_) { args = []; }
                if (args === null) continue;
                let fired = false;
                try { inst.method(rpcName, args.length).invoke(...args); fired = true; }
                catch(_) { try { inst.method(rpcName).invoke(...args); fired = true; } catch(e2) { console.error("[" + label + "] " + e2); } }
                if (fired) n++;
            }
            sendNotification(label + ": fired on " + n + "/" + all.length, false);
            return n > 0;
        } catch(e) { console.error("[" + label + "]", e); return false; }
    }
    function rpcSpawnExplosion(pos: any): boolean {
        try {
            const EM = AssemblyCSharp.class("AnimalCompany.ExplosionManager");
            if (!EM) { sendNotification("explosion: no ExplosionManager", false); return false; }
            const runner = tkGetRunner();
            if (!runner || runner.isNull?.()) { sendNotification("explosion: no runner", false); return false; }
            let explosionID = explosionIdOverride;
            if (explosionID < 0) {
                explosionID = 0;
                try {
                    const lookup = EM.field("_explosionIDLookup").value;
                    const vals = lookup.method("get_Values").invoke();
                    const en = vals.method("GetEnumerator").invoke();
                    if (en.method("MoveNext").invoke()) explosionID = en.method("get_Current").invoke() | 0;
                } catch(_) {}
            }
            let dmgInfo: any;
            try { dmgInfo = AssemblyCSharp.class("AnimalCompany.DamageSourceInfo").method("get_LocalPlayer").invoke(); }
            catch(_) { dmgInfo = tkMakeZero(AssemblyCSharp.class("AnimalCompany.DamageSourceInfo").type); }
            const rpc = EM.method("RPC_SpawnExplosion", 5);
            const infoZero = tkMakeZero(rpc.parameters[4].type);
            rpc.invoke(runner, explosionID, pos, dmgInfo, infoZero);
            sendNotification("explosion spawned (id=" + explosionID + ")", false);
            return true;
        } catch(e) { console.error("[explosion]", e); sendNotification("explosion failed (see console)", false); return false; }
    }
