    function loadBlueprintJson(): void {
        const raw = tkReadTextFile(MENU_DIR + "\\blueprint.json");
        if (!raw) { sendNotification("put a blueprint.json in " + MENU_DIR, false); return; }
        let data: any = null;
        try { data = JSON.parse(raw); } catch(_) { sendNotification("blueprint.json parse failed", false); return; }
        const anchor = readVec3Components(frontOfPlayer(2.5));
        let n = 0;
        if (data && Array.isArray(data.pieces)) n = buildGoopFromData(data, anchor);
        else if (data && Array.isArray(data.items)) {
            const pieces: any[] = [];
            for (const it of data.items) for (const ch of (it.stuckChildren || [])) { const p = ch.pos; if (p && p.length >= 3) pieces.push({ id: (ch.item && ch.item.itemID) || "item_goop", pos: [Number(p[0]) || 0, Number(p[1]) || 0, Number(p[2]) || 0], hue: (ch.item && ch.item.colorHue) || 0, sat: (ch.item && ch.item.colorSaturation) || 0, scale: (ch.item && ch.item.scaleModifier) || 0 }); }
            n = buildGoopFromData({ pieces }, anchor);
        }
        sendNotification(n > 0 ? "loaded blueprint: " + n + " pieces" : "blueprint empty / unknown format", false);
    }

