    function dumpAllItemSizes(): void {
        const MeshFilterCls = (() => { try { return Il2Cpp.domain.assembly("UnityEngine.CoreModule").image.class("UnityEngine.MeshFilter"); } catch(_) { return null; } })();
        const lines: string[] = [];
        for (const id of itemIDs) {
            let size = "?", scale = "?";
            try {
                const prefab = PrefabGen.method("GetItemPrefab", 1).invoke(Il2Cpp.string(id));
                if (prefab && !prefab.isNull?.()) {
                    try { const tf = prefab.method("get_transform").invoke(); const ls = readVec3Components(tf.method("get_localScale").invoke()); scale = ls.map((v: number) => v.toFixed(2)).join(","); } catch(_) {}
                    if (MeshFilterCls) {
                        try {
                            const go = prefab.method("get_gameObject").invoke();
                            const mf = go.method("GetComponentInChildren", 0).inflate(MeshFilterCls).invoke();
                            if (mf && !mf.isNull?.()) {
                                const mesh = mf.method("get_sharedMesh").invoke();
                                if (mesh && !mesh.isNull?.()) {
                                    const ext = readVec3Components(mesh.method("get_bounds").invoke().field("m_Extents").value);
                                    size = (ext[0] * 2).toFixed(2) + "," + (ext[1] * 2).toFixed(2) + "," + (ext[2] * 2).toFixed(2);
                                }
                            }
                        } catch(_) {}
                    }
                }
            } catch(_) {}
            lines.push(id + " | size=" + size + " | scale=" + scale);
        }
        tkWriteTextFile(MENU_DIR + "\\item_dump.txt", "items=" + lines.length + "\n" + lines.join("\n"));
        try { sendNotification("dumped " + lines.length + " items -> item_dump.txt", false); } catch(_) {}
    }

    function applyItemSwaps(): void {
        const raw = tkReadTextFile(MENU_DIR + "\\swaps.json");
        if (!raw) { sendNotification('make SOHAR\\swaps.json e.g. {"item_apple":"item_goldbar"}', false); return; }
        let map: any = null;
        try { map = JSON.parse(raw); } catch(_) { sendNotification("swaps.json parse failed", false); return; }
        let gi: any, MeshFilterCls: any, RendererCls: any;
        try {
            gi = AssemblyCSharp.class("AnimalCompany.GrabbableItem");
            MeshFilterCls = Il2Cpp.domain.assembly("UnityEngine.CoreModule").image.class("UnityEngine.MeshFilter");
            RendererCls = Il2Cpp.domain.assembly("UnityEngine.CoreModule").image.class("UnityEngine.Renderer");
        } catch(_) { sendNotification("swap: class lookup failed", false); return; }
        const donorCache: any = {};
        const getDonor = (toId: string): any => {
            if (donorCache[toId]) return donorCache[toId];
            const res: any = { mesh: null, mat: null };
            try {
                const prefab = PrefabGen.method("GetItemPrefab", 1).invoke(Il2Cpp.string(toId));
                const go = prefab.method("get_gameObject").invoke();
                try { const mf = go.method("GetComponentInChildren", 0).inflate(MeshFilterCls).invoke(); if (mf && !mf.isNull?.()) res.mesh = mf.method("get_sharedMesh").invoke(); } catch(_) {}
                try { const rd = go.method("GetComponentInChildren", 0).inflate(RendererCls).invoke(); if (rd && !rd.isNull?.()) res.mat = rd.method("get_sharedMaterial").invoke(); } catch(_) {}
            } catch(_) {}
            donorCache[toId] = res;
            return res;
        };
        let n = 0;
        try {
            const all = Object.method("FindObjectsByType", 1).inflate(gi).invoke(0);
            for (let i = 0; i < all.length; i++) {
                const it = all.get(i);
                if (!it || it.isNull?.()) continue;
                let id = ""; try { id = readItemID(it); } catch(_) {}
                const toId = map[id];
                if (!toId) continue;
                const donor = getDonor(String(toId));
                try {
                    const go = it.method("get_gameObject").invoke();
                    if (donor.mesh && !donor.mesh.isNull?.()) { const mf = go.method("GetComponentInChildren", 0).inflate(MeshFilterCls).invoke(); if (mf && !mf.isNull?.()) mf.method("set_sharedMesh").invoke(donor.mesh); }
                    if (donor.mat && !donor.mat.isNull?.()) { const rd = go.method("GetComponentInChildren", 0).inflate(RendererCls).invoke(); if (rd && !rd.isNull?.()) rd.method("set_sharedMaterial").invoke(donor.mat); }
                    n++;
                } catch(_) {}
            }
        } catch(e) { console.error("[swap]", e); }
        sendNotification("swapped look on " + n + " items (edit swaps.json + respawn for more)", false);
    }

