    let _NOClassCache: any = null;
    function tkNetworkObjectClass(): any {
        if (_NOClassCache) return _NOClassCache;
        try { _NOClassCache = Il2Cpp.domain.assembly("Fusion.Runtime").image.class("Fusion.NetworkObject"); } catch(_) {}
        return _NOClassCache;
    }
    function runnerSpawnNetworkObject(no: any, pos: any, rot: any, authPlayerRef: any = null): any {
        try {
            const runner = tkGetRunner();
            if (!runner || runner.isNull?.() || !no || no.isNull?.()) return null;
            const makeZeroForType = (type: any): any => {
                if (type.class.isEnum || type.isPrimitive) return 0;
                if (!type.class.isValueType) return NULL;
                const fields = type.class.fields.filter((f: any) => !f.isStatic);
                if (fields.length === 0) return 0;
                return fields.map((f: any) => makeZeroForType(f.type));
            };
            const buildNullableArg = (nullableType: any, hasValue: boolean, value: any): any => {
                const fields = nullableType.class.fields.filter((f: any) => !f.isStatic);
                return fields.map((f: any) => {
                    const lname = f.name.toLowerCase();
                    if (lname.includes("hasvalue")) return hasValue ? 1 : 0;
                    if (lname === "value") return hasValue ? value : makeZeroForType(f.type);
                    return makeZeroForType(f.type);
                });
            };
            const normalizeValue = (type: any, value: any): any => {
                if (typeof value === "boolean") return value ? 1 : 0;
                if (value instanceof Il2Cpp.ValueType) {
                    const fields = type.class.fields.filter((f: any) => !f.isStatic);
                    if (fields.length === 0) return 0;
                    return fields.map((f: any) => normalizeValue(f.type, f.bind(value).value));
                }
                if (Array.isArray(value)) return value.map((v: any) => normalizeValue(type, v));
                return value;
            };
            const buildNullableFromValueType = (nullableType: any, valueType: any): any => buildNullableArg(nullableType, true, normalizeValue(valueType.type, valueType));
            let spawnMethod: any = null;
            for (const m of runner.method("Spawn").overloads()) {
                if (m.parameterCount !== 6 || m.isGeneric) continue;
                const p = m.parameters;
                if (p[0].type.name.includes("Fusion.NetworkObject") &&
                    p[1].type.name.startsWith("System.Nullable") && p[1].type.name.includes("Vector3") &&
                    p[2].type.name.startsWith("System.Nullable") && p[2].type.name.includes("Quaternion") &&
                    p[3].type.name.startsWith("System.Nullable") && p[3].type.name.includes("PlayerRef") &&
                    p[4].type.name.includes("OnBeforeSpawned") &&
                    p[5].type.name.includes("NetworkSpawnFlags")) { spawnMethod = m; break; }
            }
            if (!spawnMethod) return null;
            const posArg = buildNullableFromValueType(spawnMethod.parameters[1].type, pos);
            const rotArg = buildNullableFromValueType(spawnMethod.parameters[2].type, rot || identityQuaternion);
            let authArg: any;
            if (authPlayerRef && !authPlayerRef.isNull?.()) {
                try { authArg = buildNullableFromValueType(spawnMethod.parameters[3].type, authPlayerRef); }
                catch(_) { authArg = buildNullableArg(spawnMethod.parameters[3].type, false, makeZeroForType(spawnMethod.parameters[3].type)); }
            } else {
                authArg = buildNullableArg(spawnMethod.parameters[3].type, false, makeZeroForType(spawnMethod.parameters[3].type));
            }
            const onBeforeArg = spawnMethod.parameters[4].type.class.isValueType ? makeZeroForType(spawnMethod.parameters[4].type) : NULL;
            const spawned = spawnMethod.bind(runner).invoke(no, posArg, rotArg, authArg, onBeforeArg, 0);
            if (spawned && !spawned.isNull()) spawnedNetworkPrefabs.push(spawned);
            return spawned;
        } catch(e) { console.error("[runnerSpawnNO] " + e); return null; }
    }
    function spawnMobDirect(mobEntry: { name: string; id: number }, pos: any, rot: any): any {
        try {
            acEnableMobValidatorBypass();
            let mobID = acResolveMobID(mobEntry.id);
            if (mobID == null) mobID = acResolveMobID(mobEntry.name);
            if (mobID == null && typeof mobEntry.id === "number") mobID = mobEntry.id;
            if (mobID == null) return null;
            const controller = PrefabGen.method("GetMobPrefab", 1).invoke(mobID);
            if (!controller || controller.isNull?.()) return null;
            const NO = tkNetworkObjectClass();
            let no: any = null;
            try { no = controller.method("GetComponent", 1).inflate(NO).invoke(); } catch(_) {}
            if (!no || no.isNull?.()) { try { no = controller.method("GetComponentInParent", 1).inflate(NO).invoke(); } catch(_) {} }
            if (!no || no.isNull?.()) { try { no = controller.method("GetComponentInChildren", 1).inflate(NO).invoke(); } catch(_) {} }
            if (!no || no.isNull?.()) { try { no = controller.method("get_Object").invoke(); } catch(_) {} }
            if (!no || no.isNull?.()) return null;
            let beforeDelegate = NULL;
            try { beforeDelegate = acGetBeforeMobSpawnDelegate() ?? NULL; } catch(_) { beforeDelegate = NULL; }
            const spawned = runnerSpawnNetworkObject(no, pos, rot, null);
            if (spawned && !spawned.isNull?.()) {
                try {
                    stabilizeMobInstance(spawned, pos);
                    spawnedPersistentMobs.push(spawned);
                    trackPersistentMob(mobEntry, pos, rot, spawned);
                } catch(_) {}
            }
            return spawned;
        } catch(e) { console.error("[mobDirect] " + mobEntry.name + ": " + e); return null; }
    }

