    // ── sell value that ACTUALLY survives the selling machine ──────────────
    // get_sellValue alone is client-side cosmetics; the host computes payout
    // from the networked additionalSellValue + (when we're host) SellItem.
    function installSellSurviveHook(): void {
        if (sellSurviveHookInstalled) return;
        sellSurviveHookInstalled = true;
        try {
            const gi = AssemblyCSharp.class("AnimalCompany.GrabbableItem");
            try {
                const _sv = gi.method("get_sellValue");
                _sv.implementation = function () { return sellSurviveEnabled ? SELL_VALUE : invokeInstance(_sv, this); };
            } catch(_) {}
            try {
                const _asv = gi.method("get_additionalSellValue");
                _asv.implementation = function () { return sellSurviveEnabled ? SELL_VALUE : invokeInstance(_asv, this); };
            } catch(_) {}
        } catch(e) { console.error("[sellSurvive] item hook:", e); }
        // host path: machine computes the payout itself
        try {
            const smc = AssemblyCSharp.class("AnimalCompany.ItemSellingMachineController");
            const _sell = smc.method("SellItem", 1);
            _sell.implementation = function (item: any) {
                if (sellSurviveEnabled) { try { invokeInstance(_sell, this, item); } catch(_) {} return SELL_VALUE; }
                return invokeInstance(_sell, this, item);
            };
        } catch(e) { console.error("[sellSurvive] SellItem hook:", e); }
    }
    // anti-drop: requesting state authority on a held item fires a deferred
    // StateAuthorityChanged -> HandleAnchorOrAttachmentChanged(true) -> ReleaseInternal
    // a frame later, which yanks it out of your hand. suppress that detach during
    // a short window (the bake) and, optionally, permanently (sticky hands).
    function antiDropActive(): boolean { return antiDropEnabled || time < suppressAuthDropUntil; }
    function installAntiDropHook(): void {
        if (antiDropHookInstalled) return;
        antiDropHookInstalled = true;
        try {
            const gi = AssemblyCSharp.class("AnimalCompany.GrabbableItem");
            // only skip the detach that comes from a state-authority change, so
            // normal grabbing/anchoring still works
            try {
                const _ha = gi.method("HandleAnchorOrAttachmentChanged", 1);
                _ha.implementation = function (fromStateAuthChange: any) {
                    if (antiDropActive() && fromStateAuthChange) return;
                    return invokeInstance(_ha, this, fromStateAuthChange);
                };
            } catch(_) {}
            // sticky hands: block every release while the toggle is on
            try {
                const _ri = gi.method("ReleaseInternal", 6);
                _ri.implementation = function (...args: any[]) {
                    if (antiDropEnabled) return false;
                    return invokeInstance(_ri, this, ...args);
                };
            } catch(_) {}
        } catch(e) { console.error("[antidrop]", e); }
    }
    // ── anti-dupe: neutralize the ownership/invalid-item validator ─────────
    // when your loadout/stash/blueprint loads, GrabbableItemState.Validate runs
    // ValidateInternal with removeInvalidItems + doOwnershipCheck; anything you
    // don't "own" gets deleted or replaced with a tree stick. force those flags
    // off (toggle-gated) and no-op the tree-stick swap so duped items stick.
    function installAntiDupeBypass(): void {
        if (antiDupeHookInstalled) return;
        antiDupeHookInstalled = true;
        // tree-stick replacement (invalid item -> tree stick)
        try {
            const bp = AssemblyCSharp.class("AnimalCompany.BlueprintState");
            const _rep = bp.method("ReplaceInvalidItemsWithTreeStickItemRecursive", 1);
            _rep.implementation = function (item: any) { if (antiDupeEnabled) return; return invokeInstance(_rep, this, item); };
        } catch(e) { console.error("[antidupe] treestick:", e); }
        // GrabbableItemState.Validate(removeInvalidItems, debugLogFixes, doOwnershipCheck)
        try {
            const gis = AssemblyCSharp.class("AnimalCompany.GrabbableItemState");
            const _v = gis.method("Validate", 3);
            _v.implementation = function (rem: any, dbg: any, owns: any) { return invokeInstance(_v, this, antiDupeEnabled ? false : rem, dbg, antiDupeEnabled ? false : owns); };
            const _vi = gis.method("ValidateInternal", 5);
            _vi.implementation = function (d: any, s: any, rem: any, dbg: any, owns: any) { return invokeInstance(_vi, this, d, s, antiDupeEnabled ? false : rem, dbg, antiDupeEnabled ? false : owns); };
        } catch(e) { console.error("[antidupe] GrabbableItemState:", e); }
        // loadout / template / blueprint Validate(debugLogFixes, doOwnershipCheck) -> kill ownership check
        for (const cn of ["AnimalCompany.UserLoadoutState", "AnimalCompany.UserLoadoutTemplateState", "AnimalCompany.BlueprintState"]) {
            try {
                const c = AssemblyCSharp.class(cn);
                const _v2 = c.method("Validate", 2);
                _v2.implementation = function (dbg: any, owns: any) { return invokeInstance(_v2, this, dbg, antiDupeEnabled ? false : owns); };
            } catch(_) {}
        }
        console.log("[antidupe] ownership/invalid-item validator hooks installed");
    }

    // ── container accept-any: crossbow / quiver / etc take any item ────────
    // an item container's anchor runs TryGrabObject(objectID, forceAssign, ...);
    // its checkBeforeGrab predicate rejects items it doesn't accept, so an
    // invalid item never attaches and falls. force forceAssign (+ allowSub) on
    // item-mounted anchors so containers accept anything you push in.
    function installContainerAcceptHook(): void {
        if (containerAcceptHookInstalled) return;
        containerAcceptHookInstalled = true;
        try {
            const aia = AssemblyCSharp.class("AnimalCompany.AttachedItemAnchor");
            const _tgo = aia.method("TryGrabObject", 6);
            _tgo.implementation = function (objectID: any, forceAssign: any, playSFX: any, allowSub: any, collider: any, useDefault: any) {
                if (containerAcceptAny) {
                    try {
                        // only item-mounted anchors (crossbow/quiver/backpack), never player hands
                        if (this.method("get_isOnItem").invoke() && !this.method("get_isHand").invoke()) {
                            forceAssign = true;
                            allowSub = true;
                        }
                    } catch(_) {}
                }
                return invokeInstance(_tgo, this, objectID, forceAssign, playSFX, allowSub, collider, useDefault);
            };
        } catch(e) { console.error("[containeraccept] TryGrabObject:", e); }
    }

    // bake the high value into the NETWORKED state so a remote host pays it out
    function bakeSellValueIntoItems(onlyHeld: boolean): number {
        installAntiDropHook();
        // keep the hand-detach suppressed across the deferred auth-change frame
        suppressAuthDropUntil = time + 1.5;
        let n = 0;
        const apply = (item: any) => {
            try {
                const gi = (() => { try { return item.method("GetComponent", 1).inflate(GBIClass).invoke(); } catch(_) { return null; } })();
                const target = (gi && !gi.isNull?.()) ? gi : item;
                requestStateAuthoritySafe(target);
                selfRPC(() => target.method("SetAdditionalSellValue").invoke(SELL_VALUE | 0));
                n++;
            } catch(_) {}
        };
        if (onlyHeld) {
            for (const hand of [0, 1]) {
                try { const held = getPlayerHeldGrabbable(NetPlayer.method("get_localPlayer").invoke(), hand); if (held && !held.isNull?.()) apply(held); } catch(_) {}
            }
        } else {
            for (const item of getAllLobbyItemGameObjects()) apply(item);
        }
        return n;
    }

    // ── anti-crash: heartgun + crossbow combo ──────────────────────────────
    // the combo crashes when the heart gun tries to shoot/pull a crossbow item;
    // guard every entry point on HeartGun so the bad path is swallowed instead
    // of propagating into the native crash.
    function installHeartCrossbowAntiCrash(): void {
        if (antiCrashInstalled) return;
        antiCrashInstalled = true;
        const wrap = (cls: any, name: string, argc: number) => {
            try {
                const m = (argc >= 0) ? cls.method(name, argc) : cls.method(name);
                const orig = m;
                m.implementation = function (...args: any[]) {
                    try { return invokeInstance(orig, this, ...args); }
                    catch(e) { try { console.log("[anticrash] swallowed " + name); } catch(_) {} return undefined; }
                };
            } catch(_) {}
        };
        try {
            const hg = AssemblyCSharp.class("AnimalCompany.HeartGun");
            wrap(hg, "ShootItem", -1);
            wrap(hg, "HandleShoot", -1);
            wrap(hg, "ApplyHit", 2);
            wrap(hg, "ReleaseIfHeld", 1);
            wrap(hg, "HandleTriggerPressed", -1);
            wrap(hg, "HandleTriggerRelease", -1);
        } catch(e) { console.error("[anticrash] HeartGun:", e); }
        try {
            const cb = AssemblyCSharp.class("AnimalCompany.Crossbow");
            wrap(cb, "HandleTriggerPressed", -1);
            wrap(cb, "HandleTriggerRelease", -1);
        } catch(_) {}
        console.log("[anticrash] heartgun+crossbow guards installed");
    }

