                    if (entry?.boxRoot && !entry.boxRoot.isNull?.()) Destroy(entry.boxRoot);
                    if (entry?.rayRoot && !entry.rayRoot.isNull?.()) Destroy(entry.rayRoot);
                    if (entry?.headRoot && !entry.headRoot.isNull?.()) Destroy(entry.headRoot);
                    if (entry?.textRoot && !entry.textRoot.isNull?.()) Destroy(entry.textRoot);
