            if (!quiverResult || quiverResult.isNull()) return null;
            const quiverGBO = quiverResult.method("GetComponent", 1).inflate(GBOClass).invoke();
            if (quiverGBO && !quiverGBO.isNull()) {
                quiverGBO.method("set_scaleModifier").invoke(randInt(-50, 50));
                quiverGBO.method("set_colorHue").invoke(randInt(-127, 127));
                quiverGBO.method("set_colorSaturation").invoke(randInt(-20, 127));
            }
            const container = getContainerComponent(quiverResult);
            if (!container || container.isNull()) return null;
            setContainerCapacity(container, QUIVER_ITEM_LIMIT);
            setContainerOpen(container, true);
            const pool = getQuiverFillPool();
            const insertedCount = fillContainerWithItems(container, spawnPos, QUIVER_ITEM_LIMIT, () => selectedID || pool[randInt(0, pool.length - 1)]);
            setContainerCapacity(container, QUIVER_ITEM_LIMIT);
            setContainerOpen(container, false);
