    function setContainerOpen(container, isOpen) {
        if (!container || container.isNull()) return;
        try {
            const getter = tryMethod(container, "get_isOpen", 0);
            if (getter) {
                const currentlyOpen = getter.invoke();
                if (!!currentlyOpen === !!isOpen) return;
            }
        } catch (_) { }
        try {
            const setter = tryMethod(container, "set_isOpen", 1) || tryMethod(container, "set_open", 1);
            if (setter) {
                setter.invoke(!!isOpen);
                return;
            }
        } catch (_) { }
        try {
            const fn = isOpen ? tryMethod(container, "Open", 0) : tryMethod(container, "Close", 0);
            if (fn) {
                fn.invoke();
                return;
            }
        } catch (_) { }
        try {
            const toggle = tryMethod(container, "RPC_ToggleOnOff", 0);
            if (toggle) toggle.invoke();
        } catch (_) { }
    }

    function getComponentDeep(obj: any, type) {
        let comp = getComponent(obj, type);

        if (!comp || comp.handle.isNull()) {
            comp = getComponentInParent(obj, type);
        }

        if (!comp || comp.handle.isNull()) {
            comp = getComponentInChildren(obj, type);
        }

        if (!comp || comp.handle.isNull()) {
            return null;
        }

        return comp;
    }

