    let isPlayingSound: boolean = false;
    let soundEndTime: number = 0;
    let currentPlayingClip: any = null;
    let soundPreviewObject: any = null;
    let soundPreviewSource: any = null;
    let pendingSoundLoad: any = null;

    function getFileNameWithoutExtension(path: string): string {
        const parts = path.replace(/\\/g, '/').split('/');
        const last = parts[parts.length - 1];
        const dotIdx = last.lastIndexOf('.');
        return dotIdx === -1 ? last : last.substring(0, dotIdx);
    }

    function getFileExtension(path: string): string {
        const cleanPath = path.split("?")[0].split("#")[0];
        const dotIdx = cleanPath.lastIndexOf(".");
        return dotIdx === -1 ? "" : cleanPath.substring(dotIdx + 1).toLowerCase();
    }

    function getUnityFileUrl(filePath: string): string {
        let normalized = filePath.replace(/\\/g, "/");
        if (!normalized.startsWith("/")) normalized = "/" + normalized;
        return encodeURI("file://" + normalized).replace(/#/g, "%23");
    }

    function getRecorder(): any {
        try {
            const RecorderClass = Il2Cpp.domain.assembly("PhotonVoice").image.class("Photon.Voice.Unity.Recorder");
            const recorder = Object.method("FindObjectOfType", 0).inflate(RecorderClass).invoke();
            if (recorder && !recorder.isNull()) {
                return recorder;
            }
        } catch (e) {
            console.error("[Soundboard] getRecorder error:", e);
        }
        return null;
    }

    function trySetRecorderValue(recorder: any, propertyName: string, value: any): boolean {
        try { recorder.method("set_" + propertyName).invoke(value); return true; } catch(_) {}
        try { recorder.field(propertyName).value = value; return true; } catch(_) {}
        return false;
    }

    function restartRecorder(recorder: any): void {
        try { recorder.method("StopRecording").invoke(); } catch(_) {}
        try { recorder.method("RestartRecording").invoke(); return; } catch(_) {}
        try { recorder.method("RestartRecording", 1).invoke(true); return; } catch(_) {}
        try { recorder.method("StartRecording").invoke(); } catch(_) {}
    }

    function getSoundPreviewSource(): any {
        try {
            if (soundPreviewSource && !soundPreviewSource.isNull?.()) {
                return soundPreviewSource;
            }
        } catch(_) {}

        try {
            const AudioSourceClass = UnityEngineAudio.class("UnityEngine.AudioSource");
            soundPreviewObject = createEmptyObject("__SoundboardPreview");
            try { Object.method("DontDestroyOnLoad", 1).invoke(soundPreviewObject); } catch(_) {}
            soundPreviewSource = addComponent(soundPreviewObject, AudioSourceClass);
            try { soundPreviewSource.method("set_playOnAwake").invoke(false); } catch(_) {}
            try { soundPreviewSource.method("set_loop").invoke(false); } catch(_) {}
            try { soundPreviewSource.method("set_spatialBlend").invoke(0.0); } catch(_) {}
            try { soundPreviewSource.method("set_volume").invoke(1.0); } catch(_) {}
            return soundPreviewSource;
        } catch(e) {
            console.error("[Soundboard] Could not create local preview AudioSource:", e);
            return null;
        }
    }

    function playLocalSoundPreview(clip: any): void {
        try {
            const source = getSoundPreviewSource();
            if (!source || source.isNull?.()) return;
            try { source.method("Stop").invoke(); } catch(_) {}
            source.method("set_clip").invoke(clip);
            try { source.method("set_time").invoke(0.0); } catch(_) {}
            try { source.method("set_mute").invoke(false); } catch(_) {}
            try { source.method("set_enabled").invoke(true); } catch(_) {}
            try { source.method("Play", 1).invoke(0); return; } catch(_) {}
            source.method("Play").invoke();
        } catch(e) {
            console.error("[Soundboard] Local preview failed:", e);
        }
    }

    function stopLocalSoundPreview(): void {
        try {
            if (soundPreviewSource && !soundPreviewSource.isNull?.()) {
                try { soundPreviewSource.method("Stop").invoke(); } catch(_) {}
                try { soundPreviewSource.method("set_clip").invoke(NULL); } catch(_) {}
            }
        } catch(_) {}
    }

    function stopSound(): void {
        try {
            if (pendingSoundLoad?.request && !pendingSoundLoad.request.isNull?.()) {
                try { pendingSoundLoad.request.method("Abort").invoke(); } catch(_) {}
            }
        } catch(_) {}
        pendingSoundLoad = null;
        stopLocalSoundPreview();

        const recorder = getRecorder();
        if (recorder && !recorder.isNull()) {
            try {
                trySetRecorderValue(recorder, "SourceType", 0);
                trySetRecorderValue(recorder, "AudioClip", NULL);
                trySetRecorderValue(recorder, "LoopAudioClip", false);
                trySetRecorderValue(recorder, "TransmitEnabled", true);
                restartRecorder(recorder);
                sendNotification("Sound stopped. Mic restored.", false);
            } catch (e) {
                console.error("[Soundboard] Error stopping sound:", e);
            }
        }
        isPlayingSound = false;
        currentPlayingClip = null;
    }

    function loadWavFile(filePath: string): any {
        try {
            const FileClass = Il2Cpp.domain.assembly("mscorlib").image.class("System.IO.File");
            const fileBytes = FileClass.method("ReadAllBytes", 1).invoke(Il2Cpp.string(filePath));
            if (!fileBytes || fileBytes.isNull()) {
                console.error("[Soundboard] Failed to read bytes from " + filePath);
                return null;
            }

            const len = fileBytes.length;
            const buffer = new Uint8Array(fileBytes.elements.handle.readByteArray(len));
            const view = new DataView(buffer.buffer);

            if (view.getUint32(0, true) !== 0x46464952) {
                console.error("[Soundboard] Not a valid RIFF file: " + filePath);
                return null;
            }

            if (view.getUint32(8, true) !== 0x45564157) {
                console.error("[Soundboard] Not a valid WAVE/WAV file: " + filePath);
                return null;
            }

            let offset = 12;
            let channels = 0;
            let sampleRate = 0;
            let bitsPerSample = 0;
            let dataOffset = 0;
            let dataSize = 0;

            while (offset < len - 8) {
                const chunkId = view.getUint32(offset, true);
                const chunkSize = view.getUint32(offset + 4, true);
                offset += 8;

                if (chunkId === 0x20746d66) {
                    const format = view.getUint16(offset, true);
                    if (format !== 1 && format !== 3) {
                        console.error("[Soundboard] Unsupported audio format (" + format + ") in " + filePath);
                        return null;
                    }
                    channels = view.getUint16(offset + 2, true);
                    sampleRate = view.getUint32(offset + 4, true);
                    bitsPerSample = view.getUint16(offset + 14, true);
                } else if (chunkId === 0x61746164) {
                    dataOffset = offset;
                    dataSize = chunkSize;
                    break;
                }

                offset += (chunkSize % 2 === 0) ? chunkSize : chunkSize + 1;
            }

            if (dataOffset === 0 || dataSize === 0) {
                console.error("[Soundboard] Could not find data chunk in " + filePath);
                return null;
            }

            let sampleCount = 0;
            let floatSamples: Float32Array;

            if (bitsPerSample === 16) {
                sampleCount = dataSize / 2;
                floatSamples = new Float32Array(sampleCount);
                for (let i = 0; i < sampleCount; i++) {
                    const val = view.getInt16(dataOffset + i * 2, true);
                    floatSamples[i] = val / 32768.0;
                }
            } else if (bitsPerSample === 8) {
                sampleCount = dataSize;
                floatSamples = new Float32Array(sampleCount);
                for (let i = 0; i < sampleCount; i++) {
                    const val = view.getUint8(dataOffset + i);
                    floatSamples[i] = (val - 128) / 128.0;
                }
            } else if (bitsPerSample === 32) {
                sampleCount = dataSize / 4;
                floatSamples = new Float32Array(sampleCount);
                for (let i = 0; i < sampleCount; i++) {
                    floatSamples[i] = view.getFloat32(dataOffset + i * 4, true);
                }
            } else {
                console.error("[Soundboard] Unsupported bits per sample (" + bitsPerSample + ") in " + filePath);
                return null;
            }

            const nameOnly = getFileNameWithoutExtension(filePath);
            const clipName = Il2Cpp.string(nameOnly);

            const createMethod = AudioClipClass.method("Create", 5);
            const unityClip = createMethod.invoke(clipName, sampleCount / channels, channels, sampleRate, false);

            const floatClass = Il2Cpp.domain.assembly("mscorlib").image.class("System.Single");
            const unityArray = Il2Cpp.array(floatClass, sampleCount);

            unityArray.elements.handle.writeByteArray(floatSamples.buffer);

            const setDataMethod = unityClip.method("SetData", 2);
            setDataMethod.invoke(unityArray, 0);

            return {
                clip: unityClip,
                duration: sampleCount / (sampleRate * channels),
                sampleRate: sampleRate,
                channels: channels
            };
        } catch (e) {
            console.error("[Soundboard] Error parsing WAV file:", e);
            return null;
        }
    }

    function startMp3Load(filePath: string): boolean {
    try {

        const FileClass = Il2Cpp.domain.assembly("mscorlib").image.class("System.IO.File");

        console.log("[Soundboard] Reading MP3 file bytes directly: " + filePath);

        const bytesArray = FileClass.method("ReadAllBytes", 1).invoke(Il2Cpp.string(filePath));

        if (!bytesArray || bytesArray.isNull()) {
            console.error("[Soundboard] Failed to read MP3 bytes from disk.");
            return false;
        }

        sendNotification("MP3 bytes loaded successfully!", false);
        return true;
    } catch(e) {
        console.error("[Soundboard] Error reading MP3 from disk:", e);
        return false;
    }
}

    function playLoadedSoundData(filePath: string, soundData: any): void {
        const recorder = getRecorder();
        if (!recorder || recorder.isNull()) {
            sendNotification("<color=red>Error: No voice recorder found. Join a room first.</color>", false);
            return;
        }

        try {
            const sourceOk = trySetRecorderValue(recorder, "SourceType", 1);
            const clipOk = trySetRecorderValue(recorder, "AudioClip", soundData.clip);
            const loopOk = trySetRecorderValue(recorder, "LoopAudioClip", false);
            restartRecorder(recorder);
            const transmitOk = trySetRecorderValue(recorder, "TransmitEnabled", true);
            const recordingOk = trySetRecorderValue(recorder, "RecordingEnabled", true);

            try { playLocalSoundPreview(soundData.clip); } catch(_) {}
            isPlayingSound = true;
            soundEndTime = time + soundData.duration + 0.1;
            currentPlayingClip = soundData.clip;
            console.log("[Soundboard] Starting playback for " + filePath + " duration=" + soundData.duration);
            console.log("[Soundboard] Recorder setup transmit=" + transmitOk + " recording=" + recordingOk + " loop=" + loopOk + " clip=" + clipOk + " source=" + sourceOk);

            sendNotification("Playing: " + getFileNameWithoutExtension(filePath), false);
        } catch (e) {
            console.error("[Soundboard] Error playing sound:", e);
            sendNotification("<color=red>Error starting playback.</color>", false);
        }
    }

    function finishPendingSoundLoad(): void {
        if (!pendingSoundLoad) return;
        try {
            const operation = pendingSoundLoad.operation;
            let isDone = false;
            try { isDone = operation.method("get_isDone").invoke(); } catch(_) {}
            if (!isDone) {
                if ((time || 0) - pendingSoundLoad.startedAt > 10.0) {
                    try { pendingSoundLoad.request.method("Abort").invoke(); } catch(_) {}
                    console.error("[Soundboard] MP3 decode timed out: " + pendingSoundLoad.filePath);
                    sendNotification("<color=red>MP3 decode timed out.</color>", false);
                    pendingSoundLoad = null;
                }
                return;
            }

            const load = pendingSoundLoad;
            pendingSoundLoad = null;

            try {
                const error = load.request.method("get_error").invoke();
                const errorText = String(error?.content ?? error?.toString?.() ?? "");
                if (errorText && errorText !== "null") {
                    console.error("[Soundboard] MP3 load error: " + errorText);
                }
            } catch(_) {}

            const clip = load.downloadHandlerAudioClipClass.method("GetContent", 1).invoke(load.request);
            if (!clip || clip.isNull?.()) {
                console.error("[Soundboard] Unity returned no MP3 AudioClip: " + load.filePath);
                sendNotification("<color=red>Error decoding MP3.</color>", false);
                return;
            }

            let duration = 0;
            try { duration = clip.method("get_length").invoke(); } catch(_) {}
            if (!duration || duration <= 0) duration = 1;
            playLoadedSoundData(load.filePath, { clip: clip, duration: duration, sampleRate: 0, channels: 0 });
        } catch(e) {
            console.error("[Soundboard] Error finishing sound load:", e);
            sendNotification("<color=red>Error finishing sound load.</color>", false);
            pendingSoundLoad = null;
        }
    }

    function playSound(filePath: string): void {
        if (isPlayingSound || pendingSoundLoad) {
            stopSound();
        }

        const ext = getFileExtension(filePath);
        if (ext === "wav") {
            sendNotification("Loading sound...", false);
            const soundData = loadWavFile(filePath);
            if (!soundData) {
                sendNotification("<color=red>Error loading WAV file.</color>", false);
                return;
            }
            playLoadedSoundData(filePath, soundData);
            return;
        }

        if (ext === "mp3") {
            sendNotification("Decoding MP3...", false);
            if (!startMp3Load(filePath)) {
                sendNotification("<color=red>Error starting MP3 load.</color>", false);
            }
            return;
        }

        sendNotification("<color=red>Unsupported sound file.</color>", false);
    }
function getScriptDir(): string {
        return "C:\\Program Files (x86)\\Steam\\steamapps\\common\\Animal Company";
    }

    function rebuildSoundboardButtons(): void {
        const soundboardButtons = [
            new ButtonInfo({
                buttonText: "Exit Soundboard",
                method: () => { currentCategory = 11; currentPage = 0; },
                isTogglable: false,
                toolTip: "Returns you back to the main category."
            }),
            new ButtonInfo({
                buttonText: "Reload Sounds",
                method: () => {
                    rebuildSoundboardButtons();
                    reloadMenu();
                    sendNotification("Sounds reloaded!", false);
                },
                isTogglable: false,
                toolTip: "Rescan the sounds folder for .wav and .mp3 files."
            }),
            new ButtonInfo({
                buttonText: "Stop All",
                method: () => {
                    stopSound();
                },
                isTogglable: false,
                toolTip: "Stops any playing sound and restores the microphone."
            })
        ];

        try {
            const DirectoryClass = Il2Cpp.domain.assembly("mscorlib").image.class("System.IO.Directory");
            const soundsDir = MENU_DIR + "\\sounds";
            const scanDirs = [soundsDir, getScriptDir() + "/sounds"];

            const exists = DirectoryClass.method("Exists", 1).invoke(Il2Cpp.string(soundsDir));
            if (!exists) {
                DirectoryClass.method("CreateDirectory", 1).invoke(Il2Cpp.string(soundsDir));
                console.log("[Soundboard] Created sounds directory at " + soundsDir);
            }

            const filesList: string[] = [];
            const seenSounds = new Set<string>();
            for (const dir of scanDirs) {
                try {
                    if (!DirectoryClass.method("Exists", 1).invoke(Il2Cpp.string(dir))) continue;
                    const filesArray = DirectoryClass.method("GetFiles", 2).invoke(Il2Cpp.string(dir), Il2Cpp.string("*"));
                    if (filesArray && !filesArray.isNull()) {
                        for (let i = 0; i < filesArray.length; i++) {
                            const fileValue = filesArray.get(i);
                            const filePath = String(fileValue?.content ?? fileValue?.toString?.() ?? "");
                            const ext = getFileExtension(filePath);
                            const key = getFileNameWithoutExtension(filePath).toLowerCase();
                            if ((ext === "wav" || ext === "mp3") && !seenSounds.has(key)) { seenSounds.add(key); filesList.push(filePath); }
                        }
                    }
                } catch(_) {}
            }
            console.log("[Soundboard] Scanned " + scanDirs.join(" + ") + " and found " + filesList.length + " sound file(s)");

            if (filesList.length === 0) {
                soundboardButtons.push(new ButtonInfo({
                    buttonText: "No sounds found",
                    method: () => {
                        sendNotification("Add .wav or .mp3 files to " + soundsDir, false);
                    },
                    isTogglable: false,
                    toolTip: "Put your .wav or .mp3 files in the menu's 'sounds' folder!"
                }));
            } else {
                for (const filePath of filesList) {
                    const nameOnly = getFileNameWithoutExtension(filePath);
                    soundboardButtons.push(new ButtonInfo({
                        buttonText: nameOnly,
                        method: () => {
                            playSound(filePath);
                        },
                        isTogglable: false,
                        toolTip: "Play " + nameOnly
                    }));
                }
            }
        } catch (e) {
            console.error("[Soundboard] Error scanning directory:", e);
        }

        buttons[32] = soundboardButtons;
        rebuildButtonMap();
    }

