                gw.push(new ButtonInfo({ buttonText: "gk_back", method: () => { goopWriteText = goopWriteText.slice(0, -1); }, isTogglable: false }));
                gw.push(new ButtonInfo({ buttonText: "gk_clear", method: () => { goopWriteText = ""; }, isTogglable: false }));
                // results / actions (rendered in the keyboard's results list, in order)
                gw.push(new ButtonInfo({ buttonText: "gres_0", method: () => { writeGoopAt(frontOfPlayer(3.0)); }, isTogglable: false }));
                gw.push(new ButtonInfo({ buttonText: "gres_1", isTogglable: true, method: () => { if (!rightGrab) return; const gd = renderGun(); if (!rightTrigger || time <= goopGunDelay) return; goopGunDelay = time + 0.6; writeGoopAt(gd.endPosition); }, toolTip: "aim + trigger to stamp your word in goop where you point." }));
