                gw.push(new ButtonInfo({ buttonText: "gres_3", method: () => { goopWriteScale = Math.max(0.06, goopWriteScale - 0.03); sendNotification("goop letter size: " + goopWriteScale.toFixed(2), false); }, isTogglable: false }));
